import fs from "node:fs";
import path from "node:path";
import { gzipSync, gunzipSync } from "node:zlib";

const ARCHIVE_KIND = "xananode.substrate";
const ARCHIVE_MEDIA_TYPE = "application/vnd.xananode.substrate+json+gzip";
const ARCHIVE_VERSION = "0.1.0";
const SKIP_DIRS = new Set([".git", "node_modules", "public", "resources", ".hugo_cache"]);

export function isSubstrateArchive(filePath) {
  return String(filePath || "").toLowerCase().endsWith(".substrate");
}

export function createSubstrateArchive(sourceDir, archivePath, options = {}) {
  const rootDir = path.resolve(sourceDir);
  const files = collectArchiveFiles(rootDir);
  const archive = {
    kind: ARCHIVE_KIND,
    media_type: ARCHIVE_MEDIA_TYPE,
    archive_version: ARCHIVE_VERSION,
    created_at: options.createdAt || new Date().toISOString(),
    source: options.source || {},
    manifest: options.manifest || readJsonIfExists(path.join(rootDir, "substrate.json")),
    files: files.map((relativePath) => {
      const absolutePath = path.join(rootDir, relativePath);
      return {
        path: relativePath.replace(/\\/g, "/"),
        encoding: "base64",
        content: fs.readFileSync(absolutePath).toString("base64")
      };
    })
  };

  fs.mkdirSync(path.dirname(archivePath), { recursive: true });
  fs.writeFileSync(archivePath, gzipSync(Buffer.from(JSON.stringify(archive), "utf8"), { level: 9 }));
  return {
    archivePath,
    file_count: archive.files.length,
    manifest: archive.manifest,
    source: archive.source
  };
}

export function readSubstrateArchive(filePath) {
  const archive = parseSubstrateArchiveBuffer(fs.readFileSync(filePath), filePath);
  if (archive.kind !== ARCHIVE_KIND) {
    throw new Error(`Not a XanaNode substrate archive: ${filePath}`);
  }
  if (!Array.isArray(archive.files) && !isDirectSubstrateEnvelope(archive)) {
    throw new Error(`XanaNode substrate archive has neither a files array nor direct substrate records: ${filePath}`);
  }
  return archive;
}

export function readSubstrateArchiveManifest(filePath) {
  return readSubstrateArchive(filePath).manifest || {};
}

export function extractSubstrateArchive(filePath, targetDir, options = {}) {
  const archive = readSubstrateArchive(filePath);
  const resolvedTarget = path.resolve(targetDir);
  if (fs.existsSync(resolvedTarget) && fs.readdirSync(resolvedTarget).length && options.overwrite !== true) {
    throw new Error(`Target directory is not empty: ${resolvedTarget}`);
  }
  fs.mkdirSync(resolvedTarget, { recursive: true });
  if (Array.isArray(archive.files)) {
    for (const file of archive.files) {
      const safePath = safeArchivePath(resolvedTarget, file.path);
      fs.mkdirSync(path.dirname(safePath), { recursive: true });
      fs.writeFileSync(safePath, Buffer.from(file.content || "", file.encoding === "base64" ? "base64" : "utf8"));
    }
  } else {
    materializeDirectEnvelopeArchive(archive, resolvedTarget);
  }
  return {
    targetDir: resolvedTarget,
    manifest: archive.manifest || readJsonIfExists(path.join(resolvedTarget, "substrate.json")),
    source: archive.source || {},
    file_count: Array.isArray(archive.files) ? archive.files.length : countMaterializedEnvelopeFiles(archive)
  };
}

export function substrateArchiveFileName(manifest = {}, source = {}) {
  const namespace = slugPart(manifest.namespace || manifest.id || manifest.name || "substrate");
  const branch = slugPart(source.git_branch || manifest.repository?.default_branch || "branch");
  const commit = slugPart(String(source.git_commit || manifest.repository?.commit || "uncommitted").slice(0, 12));
  return `${namespace}-${branch}-${commit}.substrate`;
}

function collectArchiveFiles(rootDir) {
  const files = [];
  walk(rootDir, rootDir, files);
  return files.sort((a, b) => a.localeCompare(b));
}

function walk(rootDir, currentDir, files) {
  for (const entry of fs.readdirSync(currentDir, { withFileTypes: true })) {
    if (entry.name === ".xananode") {
      walkXananode(rootDir, path.join(currentDir, entry.name), files);
      continue;
    }
    if (entry.isDirectory() && SKIP_DIRS.has(entry.name)) continue;
    const fullPath = path.join(currentDir, entry.name);
    if (entry.isDirectory()) {
      walk(rootDir, fullPath, files);
    } else if (entry.isFile()) {
      files.push(path.relative(rootDir, fullPath));
    }
  }
}

function walkXananode(rootDir, currentDir, files) {
  for (const entry of fs.readdirSync(currentDir, { withFileTypes: true })) {
    if (entry.name === "preview-hugo" || entry.name.startsWith("preview-hugo-")) continue;
    const fullPath = path.join(currentDir, entry.name);
    if (entry.isDirectory()) walkXananode(rootDir, fullPath, files);
    else if (entry.isFile()) files.push(path.relative(rootDir, fullPath));
  }
}

function safeArchivePath(rootDir, relativePath) {
  const resolved = path.resolve(rootDir, String(relativePath || ""));
  if (resolved !== rootDir && !resolved.startsWith(`${rootDir}${path.sep}`)) {
    throw new Error(`Unsafe archive path: ${relativePath}`);
  }
  return resolved;
}

function readJsonIfExists(filePath) {
  try {
    if (fs.existsSync(filePath)) return JSON.parse(fs.readFileSync(filePath, "utf8"));
  } catch {
    return null;
  }
  return null;
}

function slugPart(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 64) || "unknown";
}

function parseSubstrateArchiveBuffer(buffer, filePath) {
  const source = Buffer.isBuffer(buffer) ? buffer : Buffer.from(buffer || "");
  if (!source.length) {
    throw new Error(`XanaNode substrate archive is empty: ${filePath}`);
  }

  if (looksLikeZip(source)) {
    throw new Error(
      `Unsupported substrate container: ${filePath}. Studio/Workspace expects a gzip-wrapped .substrate archive or a plain JSON substrate envelope, not a .zip file.`
    );
  }

  const utf8 = source.toString("utf8").trimStart();
  if (utf8.startsWith("{")) {
    try {
      return JSON.parse(utf8);
    } catch (error) {
      throw new Error(`Could not parse plain JSON substrate archive ${filePath}: ${error.message}`);
    }
  }

  try {
    return JSON.parse(gunzipSync(source).toString("utf8"));
  } catch (error) {
    throw new Error(`Could not read substrate archive ${filePath}: expected gzip-wrapped JSON or plain JSON envelope. ${error.message}`);
  }
}

function looksLikeZip(buffer) {
  return buffer.length >= 4
    && buffer[0] === 0x50
    && buffer[1] === 0x4b
    && (buffer[2] === 0x03 || buffer[2] === 0x05 || buffer[2] === 0x07)
    && (buffer[3] === 0x04 || buffer[3] === 0x06 || buffer[3] === 0x08);
}

function isDirectSubstrateEnvelope(value) {
  return Boolean(
    value
    && typeof value === "object"
    && Array.isArray(value.nodes)
    && Array.isArray(value.relationships)
  );
}

function materializeDirectEnvelopeArchive(archive, targetDir) {
  const manifest = archive.manifest && typeof archive.manifest === "object" ? archive.manifest : {};
  fs.writeFileSync(path.join(targetDir, "substrate.json"), JSON.stringify(manifest, null, 2));
  fs.writeFileSync(path.join(targetDir, "nodes.json"), JSON.stringify({ nodes: archive.nodes || [] }, null, 2));
  fs.writeFileSync(path.join(targetDir, "relationships.json"), JSON.stringify({ relationships: archive.relationships || [] }, null, 2));
}

function countMaterializedEnvelopeFiles() {
  return 3;
}

import path from "node:path";
import { ensureDir, readJsonFile, writeJsonFile } from "./fs-utils.js";

export function authorsPath(rootDir) {
  return path.join(rootDir, ".xananode", "authors.json");
}

export function loadAuthors(rootDir) {
  return readJsonFile(authorsPath(rootDir), { authors: [], default_author_id: null });
}

export function saveAuthors(rootDir, authorsFile) {
  ensureDir(path.join(rootDir, ".xananode"));
  return writeJsonFile(authorsPath(rootDir), authorsFile);
}

export function upsertAuthor(rootDir, author) {
  if (!author?.id) throw new Error("Author id is required");
  const file = loadAuthors(rootDir);
  const index = file.authors.findIndex((existing) => existing.id === author.id);
  const normalized = {
    id: author.id,
    name: author.name || author.id,
    email: author.email,
    website: author.website,
    github: author.github,
    orcid: author.orcid,
    public_key: author.public_key,
    default_license: author.default_license,
    roles: author.roles || ["author"],
    created_at: author.created_at || new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
  if (index >= 0) file.authors[index] = { ...file.authors[index], ...normalized };
  else file.authors.push(normalized);
  if (author.default === true || !file.default_author_id) file.default_author_id = author.id;
  saveAuthors(rootDir, file);
  return normalized;
}

export function getDefaultAuthor(rootDir) {
  const file = loadAuthors(rootDir);
  return file.authors.find((author) => author.id === file.default_author_id) || file.authors[0] || null;
}

import path from "node:path";
import { Command } from "commander";
import {
  addImport,
  buildWorkspace,
  computeKnowledgeHealth,
  createNode,
  exportWorkspacePack,
  cloneFederationTarget,
  gitLog,
  gitStatus,
  importAssetAsNode,
  initWorkspace,
  listFederationTargets,
  mountFederationTarget,
  openPackAsWorkspace,
  openWorkspace,
  saveSnapshot,
  upsertAuthor,
  validateWorkspace
} from "./index.js";

const WORKSPACE_CLI_VERSION = "0.1.0";

function printJson(value) {
  console.log(JSON.stringify(value, null, 2));
}

function commandEnvelope(command, data, extras = {}) {
  return {
    ok: true,
    tool: "xananode-workspace",
    version: WORKSPACE_CLI_VERSION,
    command,
    ...extras,
    data
  };
}

function printHealth(health) {
  console.log(`Knowledge Health: ${health.score}%`);
  console.log(`Nodes: ${health.counts.nodes}`);
  console.log(`Relationships: ${health.counts.relationships}`);
  console.log(`Fragments: ${health.counts.fragments}`);
  console.log(`Suggestions: ${health.counts.suggestions}`);
  console.log(`Applied suggestions: ${health.counts.applied_suggestions || 0}`);
  console.log(`Issues: ${health.counts.issues}`);
  if (health.issues.length) {
    console.log("\nTop issues:");
    for (const issue of health.issues.slice(0, 15)) {
      console.log(`- ${issue.severity || "info"}: ${issue.kind || issue.label || "issue"} ${issue.node || issue.relationship || ""}`.trim());
    }
  }
}

function workspaceSummary(workspace) {
  return {
    root_dir: workspace.rootDir,
    manifest: workspace.manifest,
    counts: {
      nodes: workspace.nodes.length,
      authors: workspace.authors.authors.length,
      imports: workspace.imports.imports.length
    },
    git: {
      enabled: workspace.git.enabled
    }
  };
}

export async function runWorkspaceCli(argv = process.argv) {
  const program = new Command();
  program
    .name("xananode-workspace")
    .description("Local-first workspace engine CLI for XanaNode Studio")
    .version(WORKSPACE_CLI_VERSION);

  program.command("init")
    .argument("[dir]", "workspace directory", ".")
    .option("--name <name>", "substrate name", "New XanaNode Substrate")
    .option("--namespace <namespace>", "substrate namespace")
    .option("--author <name>", "default author name")
    .option("--author-id <id>", "default author id")
    .option("--author-email <email>", "default author email")
    .option("--no-git", "do not initialize a Git repository")
    .option("--with-hugo", "enable the Hugo projection layer for this workspace")
    .option("--json", "print machine-readable JSON")
    .description("create a XanaNode substrate and workspace metadata")
    .action(async (dir, options) => {
      options.includeHugo = options.withHugo === true;
      const workspace = await initWorkspace(path.resolve(dir), options);
      if (options.json) return printJson(commandEnvelope("init", workspaceSummary(workspace)));
      console.log(`Created XanaNode workspace: ${workspace.manifest.name}`);
      console.log(`Namespace: ${workspace.manifest.namespace}`);
      console.log(`Path: ${workspace.rootDir}`);
    });

  program.command("open")
    .argument("[dir]", "workspace directory", ".")
    .option("--json", "print raw JSON")
    .description("read a workspace summary")
    .action(async (dir, options) => {
      const workspace = await openWorkspace(path.resolve(dir));
      if (options.json) return printJson(commandEnvelope("open", workspaceSummary(workspace)));
      console.log(`${workspace.manifest.name} (${workspace.manifest.namespace})`);
      console.log(`Nodes: ${workspace.nodes.length}`);
      console.log(`Authors: ${workspace.authors.authors.length}`);
      console.log(`Imports: ${workspace.imports.imports.length}`);
      console.log(`Git: ${workspace.git.enabled ? "enabled" : "not initialized"}`);
    });

  program.command("open-pack")
    .argument("<pack>", "pack folder or pack JSON file")
    .argument("[dir]", "workspace directory to create")
    .option("--name <name>", "working copy name")
    .option("--namespace <namespace>", "working copy namespace")
    .option("--author <name>", "active author name")
    .option("--author-id <id>", "active author id")
    .option("--author-email <email>", "active author email")
    .option("--no-git", "do not initialize a Git repository")
    .option("--json", "print machine-readable JSON")
    .description("open an existing substrate bundle as an editable local working copy")
    .action(async (pack, dir, options) => {
      const target = path.resolve(dir || `${path.basename(path.resolve(pack))}-working-copy`);
      const workspace = await openPackAsWorkspace(path.resolve(pack), target, options);
      if (options.json) {
        return printJson(commandEnvelope("open-pack", {
          ...workspaceSummary(workspace),
          source_pack: workspace.settings.source_pack?.id || workspace.manifest.source_pack?.id || null
        }));
      }
      console.log(`Opened pack as working copy: ${workspace.manifest.name}`);
      console.log(`Source pack: ${workspace.settings.source_pack?.id || workspace.manifest.source_pack?.id || "unknown"}`);
      console.log(`Nodes: ${workspace.nodes.length}`);
      console.log(`Path: ${workspace.rootDir}`);
    });

  program.command("status")
    .alias("health")
    .argument("[dir]", "workspace directory", ".")
    .option("--json", "print raw JSON")
    .description("show knowledge health and Git state")
    .action(async (dir, options) => {
      const rootDir = path.resolve(dir);
      const health = await computeKnowledgeHealth(rootDir);
      const status = gitStatus(rootDir);
      if (options.json) {
        return printJson(commandEnvelope("health", {
          root_dir: rootDir,
          health,
          git: status
        }));
      }
      printHealth(health);
      console.log(`\nGit changes: ${status.changed.length}`);
      for (const change of status.changed.slice(0, 15)) console.log(`- ${change.code} ${change.path}`);
    });

  program.command("validate")
    .argument("[dir]", "workspace directory", ".")
    .option("--json", "print machine-readable JSON")
    .description("validate the substrate through @xananode/core")
    .action(async (dir, options) => {
      const validation = await validateWorkspace(path.resolve(dir));
      if (options.json) {
        printJson(commandEnvelope("validate", {
          root_dir: path.resolve(dir),
          validation
        }));
      } else {
        printJson(validation);
      }
      process.exitCode = validation.valid ? 0 : 1;
    });

  program.command("build")
    .argument("[dir]", "workspace directory", ".")
    .option("--out <dir>", "artifact output directory")
    .option("--suggestions-mode <mode>", "review or apply", "review")
    .option("--no-split-artifacts", "skip substrate.json, relationships.json, and nodes/*.json")
    .option("--no-bundle-json", "skip substrate-bundle.json")
    .option("--bundle-jsonl", "also write substrate-bundle.jsonl", false)
    .option("--json", "print machine-readable JSON")
    .description("build protocol artifacts through @xananode/core")
    .action(async (dir, options) => {
      const result = await buildWorkspace(path.resolve(dir), {
        ...options,
        core: {
          suggestionMode: options.suggestionsMode
        }
      });
      if (options.json) {
        return printJson(commandEnvelope("build", {
          root_dir: path.resolve(dir),
          output_dir: result.outputDir,
          manifest: result.substrate.manifest,
          counts: {
            nodes: result.substrate.protocolNodes.length,
            relationships: result.substrate.relationships.length,
            applied_suggestions: result.substrate.applied_suggestions?.length || 0
          },
          validation: result.substrate.validation
        }));
      }
      console.log(`Built substrate artifacts to ${result.outputDir}`);
      console.log(`Nodes: ${result.substrate.protocolNodes.length}`);
      console.log(`Relationships: ${result.substrate.relationships.length}`);
      console.log(`Applied suggestions: ${result.substrate.applied_suggestions?.length || 0}`);
      console.log(`Valid: ${result.substrate.validation.valid}`);
    });

  program.command("pack")
    .alias("export")
    .argument("[dir]", "workspace directory", ".")
    .option("--out <dir>", "pack output directory")
    .option("--id <id>", "pack id")
    .option("--name <name>", "pack name")
    .option("--namespace <namespace>", "pack namespace")
    .option("--version <version>", "pack version")
    .option("--mode <mode>", "pack composition mode", "mounted")
    .option("--suggestions-mode <mode>", "review or apply", "review")
    .option("--no-archive", "write only the unpacked pack folder")
    .option("--no-split-artifacts", "skip substrate.json, nodes.json, relationships.json, and nodes/*.json")
    .option("--no-bundle-json", "skip substrate-bundle.json")
    .option("--bundle-jsonl", "also write substrate-bundle.jsonl", false)
    .option("--json", "print machine-readable JSON")
    .description("export a portable substrate bundle for renderers and other tools")
    .action(async (dir, options) => {
      options.archive = options.archive !== false;
      const result = await exportWorkspacePack(path.resolve(dir), {
        ...options,
        suggestionMode: options.suggestionsMode
      });
      if (options.json) {
        return printJson(commandEnvelope("export", {
          root_dir: path.resolve(dir),
          output_dir: result.outputDir,
          archive_path: result.archivePath,
          manifest: result.pack.manifest,
          counts: {
            nodes: result.pack.node_count,
            relationships: result.pack.relationship_count
          }
        }));
      }
      console.log(`Exported substrate pack to ${result.outputDir}`);
      if (result.archivePath) console.log(`Archive: ${result.archivePath}`);
      console.log(`Pack: ${result.pack.manifest.id}`);
      console.log(`Nodes: ${result.pack.node_count}`);
      console.log(`Relationships: ${result.pack.relationship_count}`);
    });

  program.command("federation-targets")
    .option("--json", "print raw JSON")
    .description("list known online substrate federation targets from the protocol registry")
    .action((options) => {
      const targets = listFederationTargets();
      if (options.json) return printJson(commandEnvelope("federation-targets", { federation_targets: targets }));
      for (const target of targets) {
        console.log(`${target.id} - ${target.name}`);
        console.log(`  ${target.repository?.url || ""}`);
      }
    });

  program.command("federate")
    .argument("[dir]", "workspace directory", ".")
    .requiredOption("--target <id>", "federation target id or namespace")
    .option("--into <dir>", "clone destination directory")
    .option("--branch <branch>", "branch to clone")
    .option("--mode <mode>", "mount mode", "mounted")
    .option("--json", "print machine-readable JSON")
    .description("clone a known online substrate target and mount it into this workspace")
    .action((dir, options) => {
      const rootDir = path.resolve(dir);
      const cloneDir = path.resolve(options.into || path.join(rootDir, ".xananode", "federation", options.target));
      const cloned = cloneFederationTarget(options.target, cloneDir, options);
      const mounted = mountFederationTarget(rootDir, cloned, { mode: options.mode });
      const payload = { cloned, mounted };
      if (options.json) return printJson(commandEnvelope("federate", payload));
      printJson(payload);
    });

  program.command("author")
    .argument("[dir]", "workspace directory")
    .requiredOption("--id <id>", "author id")
    .requiredOption("--name <name>", "author name")
    .option("--email <email>", "author email")
    .option("--github <handle>", "GitHub handle")
    .option("--default", "make default author")
    .option("--json", "print machine-readable JSON")
    .description("add or update an author profile")
    .action((dir, options) => {
      const author = upsertAuthor(path.resolve(dir), options);
      if (options.json) return printJson(commandEnvelope("author", author));
      printJson(author);
    });

  program.command("node")
    .argument("[dir]", "workspace directory")
    .requiredOption("--title <title>", "node title")
    .option("--type <type>", "node type", "concept")
    .option("--summary <summary>", "node summary", "")
    .option("--json", "print machine-readable JSON")
    .description("create a new node file")
    .action(async (dir, options) => {
      const result = await createNode(path.resolve(dir), options, `# ${options.title}\n\n`);
      if (options.json) return printJson(commandEnvelope("node", result));
      console.log(`Created node: ${result.filePath}`);
    });

  program.command("asset")
    .argument("[dir]", "workspace directory")
    .argument("<file>", "file to import")
    .option("--title <title>", "asset node title")
    .option("--type <type>", "media or source")
    .option("--json", "print machine-readable JSON")
    .description("copy an asset into the workspace and create a source/media node")
    .action(async (dir, file, options) => {
      const result = await importAssetAsNode(path.resolve(dir), path.resolve(file), options);
      if (options.json) return printJson(commandEnvelope("asset", result));
      printJson(result);
    });

  program.command("import")
    .argument("[dir]", "workspace directory")
    .requiredOption("--id <id>", "substrate id")
    .option("--url <url>", "substrate repository or manifest URL")
    .option("--version <version>", "version constraint", "latest")
    .option("--mode <mode>", "reference, clone, submodule, package", "reference")
    .option("--json", "print machine-readable JSON")
    .description("record an imported/federated substrate dependency")
    .action((dir, options) => {
      const result = addImport(path.resolve(dir), options);
      if (options.json) return printJson(commandEnvelope("import", result));
      printJson(result);
    });

  program.command("save")
    .alias("snapshot")
    .argument("[dir]", "workspace directory", ".")
    .option("--message <message>", "snapshot message")
    .option("--author-name <name>", "Git author name")
    .option("--author-email <email>", "Git author email")
    .option("--json", "print machine-readable JSON")
    .description("save a Git-backed workspace snapshot")
    .action((dir, options) => {
      const result = saveSnapshot(path.resolve(dir), options);
      if (options.json) return printJson(commandEnvelope("snapshot", result));
      printJson(result);
    });

  program.command("history")
    .argument("[dir]", "workspace directory", ".")
    .option("--limit <n>", "number of snapshots", "25")
    .option("--json", "print machine-readable JSON")
    .description("show saved workspace snapshots")
    .action((dir, options) => {
      const result = gitLog(path.resolve(dir), Number(options.limit));
      if (options.json) return printJson(commandEnvelope("history", result));
      printJson(result);
    });

  await program.parseAsync(argv);
}

import fs from "node:fs";
import path from "node:path";
import { spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { addImport } from "./imports.js";
import { gitRevision } from "./git.js";

const workspacePackageRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const bundledProtocolRoot = path.join(workspacePackageRoot, "vendor", "xananode-core", "vendor", "xananode-protocol");

export function loadFederationTargets(options = {}) {
  const registryPath = options.registryPath || path.join(bundledProtocolRoot, "registry", "federation-targets.json");
  if (!fs.existsSync(registryPath)) return { federation_targets: [] };
  return JSON.parse(fs.readFileSync(registryPath, "utf8"));
}

export function listFederationTargets(options = {}) {
  return loadFederationTargets(options).federation_targets || [];
}

export function cloneFederationTarget(target, destinationDir, options = {}) {
  const record = typeof target === "string"
    ? listFederationTargets(options).find((candidate) => candidate.id === target || candidate.namespace === target)
    : target;
  if (!record?.repository?.url) throw new Error(`Unknown federation target: ${target}`);

  const branch = options.branch || record.repository.branch || record.repository.default_branch || "main";
  const targetDir = path.resolve(destinationDir);
  const clone = spawnSync("git", ["clone", "--branch", branch, record.repository.url, targetDir], {
    encoding: "utf8",
    shell: false
  });
  if (clone.status !== 0) throw new Error(clone.stderr || clone.stdout || `Failed to clone federation target ${record.id}`);

  const revision = gitRevision(targetDir);
  return {
    target: record,
    path: targetDir,
    branch: revision.branch || branch,
    commit: revision.commit || "",
    name: federatedSubstrateName(record, revision.branch || branch, revision.commit || "")
  };
}

export function mountFederationTarget(rootDir, clonedTarget, options = {}) {
  const target = clonedTarget.target || clonedTarget;
  const branch = clonedTarget.branch || target.repository?.branch || target.repository?.default_branch || "main";
  const commit = clonedTarget.commit || target.repository?.commit || "";
  return addImport(rootDir, {
    id: target.id || target.namespace,
    source: options.source || clonedTarget.path || target.repository?.url,
    mode: options.mode || "mounted",
    version: commit ? `${branch}@${commit}` : branch,
    description: target.description || "",
    required: options.required === true,
    repository: {
      type: "git",
      url: target.repository?.url,
      branch,
      commit
    }
  });
}

export function federatedSubstrateName(target, branch, commit) {
  const shortCommit = String(commit || "unresolved").slice(0, 12);
  return `${target.name || target.id || target.namespace} (${branch}@${shortCommit})`;
}

import fs from "node:fs";
import path from "node:path";

export function pathExists(filePath) {
  return fs.existsSync(filePath);
}

export function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
  return dirPath;
}

export function readJsonFile(filePath, fallback = undefined) {
  if (!fs.existsSync(filePath)) return fallback;
  return JSON.parse(fs.readFileSync(filePath, "utf8"));
}

export function writeJsonFile(filePath, value) {
  ensureDir(path.dirname(filePath));
  fs.writeFileSync(filePath, `${JSON.stringify(value, null, 2)}\n`);
  return filePath;
}

export function readTextFile(filePath, fallback = "") {
  if (!fs.existsSync(filePath)) return fallback;
  return fs.readFileSync(filePath, "utf8");
}

export function writeTextFile(filePath, value) {
  ensureDir(path.dirname(filePath));
  fs.writeFileSync(filePath, String(value));
  return filePath;
}

export function copyFileIntoDirectory(sourceFile, destinationDir, destinationName = path.basename(sourceFile)) {
  ensureDir(destinationDir);
  const destination = path.join(destinationDir, destinationName);
  fs.copyFileSync(sourceFile, destination);
  return destination;
}

export function safeRelativePath(rootDir, candidatePath) {
  const resolvedRoot = path.resolve(rootDir);
  const resolvedCandidate = path.resolve(rootDir, candidatePath);
  const relative = path.relative(resolvedRoot, resolvedCandidate);
  if (relative.startsWith("..") || path.isAbsolute(relative)) {
    throw new Error(`Path escapes workspace root: ${candidatePath}`);
  }
  return resolvedCandidate;
}

export function listFilesRecursive(rootDir, predicate = () => true) {
  const results = [];
  if (!fs.existsSync(rootDir)) return results;
  for (const entry of fs.readdirSync(rootDir, { withFileTypes: true })) {
    const fullPath = path.join(rootDir, entry.name);
    if (entry.isDirectory()) results.push(...listFilesRecursive(fullPath, predicate));
    else if (predicate(fullPath)) results.push(fullPath);
  }
  return results;
}

import { spawnSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";

export function hasGit(rootDir) {
  return fs.existsSync(path.join(rootDir, ".git"));
}

export function runGit(rootDir, args, options = {}) {
  const result = spawnSync("git", args, {
    cwd: rootDir,
    encoding: "utf8",
    shell: false,
    ...options
  });
  return {
    ok: result.status === 0,
    status: result.status,
    stdout: result.stdout || "",
    stderr: result.stderr || "",
    args
  };
}

export function ensureGitRepo(rootDir, options = {}) {
  if (hasGit(rootDir)) return { initialized: false, alreadyExisted: true };
  const init = runGit(rootDir, ["init", "-b", options.defaultBranch || "main"]);
  if (!init.ok) {
    const fallback = runGit(rootDir, ["init"]);
    if (!fallback.ok) throw new Error(fallback.stderr || fallback.stdout || "Failed to initialize Git repository");
  }
  return { initialized: true, alreadyExisted: false };
}

export function gitStatus(rootDir) {
  if (!hasGit(rootDir)) return { available: false, changed: [], raw: "" };
  const result = runGit(rootDir, ["status", "--porcelain=v1"]);
  if (!result.ok) return { available: false, error: result.stderr || result.stdout, changed: [], raw: "" };
  const changed = result.stdout.split(/\r?\n/).filter(Boolean).map((line) => ({
    code: line.slice(0, 2),
    path: line.slice(3)
  }));
  return { available: true, changed, raw: result.stdout };
}

export function gitLog(rootDir, limit = 25) {
  if (!hasGit(rootDir)) return [];
  const result = runGit(rootDir, ["log", `-${limit}`, "--pretty=format:%H%x1f%an%x1f%ae%x1f%ad%x1f%s", "--date=iso"]);
  if (!result.ok) return [];
  return result.stdout.split(/\r?\n/).filter(Boolean).map((line) => {
    const [hash, authorName, authorEmail, date, subject] = line.split("\x1f");
    return { hash, authorName, authorEmail, date, subject };
  });
}

export function gitRevision(rootDir) {
  if (!hasGit(rootDir)) {
    return {
      available: false,
      branch: "",
      commit: "",
      dirty: false
    };
  }
  const branch = runGit(rootDir, ["rev-parse", "--abbrev-ref", "HEAD"]);
  const commit = runGit(rootDir, ["rev-parse", "HEAD"]);
  const status = gitStatus(rootDir);
  return {
    available: branch.ok && commit.ok,
    branch: branch.ok ? branch.stdout.trim() : "",
    commit: commit.ok ? commit.stdout.trim() : "",
    dirty: Boolean(status.changed?.length),
    changed: status.changed || []
  };
}

export function saveSnapshot(rootDir, options = {}) {
  if (!hasGit(rootDir)) ensureGitRepo(rootDir, options);
  const add = runGit(rootDir, [
    "add",
    "-A",
    "--",
    ".",
    ":(exclude).xananode/preview-hugo*"
  ]);
  if (!add.ok) throw new Error(add.stderr || add.stdout || "Failed to stage workspace changes");
  const status = gitStatus(rootDir);
  if (!status.changed.length) return { committed: false, message: "No changes to save", status };
  const message = options.message || "Save XanaNode workspace snapshot";
  const env = { ...process.env };
  if (options.authorName) env.GIT_AUTHOR_NAME = options.authorName;
  if (options.authorEmail) env.GIT_AUTHOR_EMAIL = options.authorEmail;
  if (options.authorName) env.GIT_COMMITTER_NAME = options.authorName;
  if (options.authorEmail) env.GIT_COMMITTER_EMAIL = options.authorEmail;
  const commit = runGit(rootDir, ["commit", "-m", message], { env });
  if (!commit.ok) throw new Error(commit.stderr || commit.stdout || "Failed to commit workspace snapshot");
  return { committed: true, message, output: commit.stdout, status: gitStatus(rootDir) };
}

import { buildSubstrate, stripMarkdown } from "@xananode/core";
import { gitStatus } from "./git.js";

function percentage(score, max) {
  if (max <= 0) return 100;
  return Math.max(0, Math.min(100, Math.round((score / max) * 100)));
}

function normalizeComparableText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

export async function computeKnowledgeHealth(rootDir, options = {}) {
  const substrate = await buildSubstrate(rootDir, options.core || {});
  const nodes = substrate.protocolNodes || [];
  const relationships = substrate.relationships || [];
  const nodeIds = new Set(nodes.map((node) => node.id));
  const incoming = new Map(nodes.map((node) => [node.id, 0]));
  const outgoing = new Map(nodes.map((node) => [node.id, 0]));
  const issues = [];

  for (const relationship of relationships) {
    if (incoming.has(relationship.target)) incoming.set(relationship.target, incoming.get(relationship.target) + 1);
    if (outgoing.has(relationship.source)) outgoing.set(relationship.source, outgoing.get(relationship.source) + 1);
    if (!relationship.external && relationship.source && !nodeIds.has(relationship.source)) {
      issues.push({ severity: "warning", kind: "missing_source_node", relationship: relationship.id, source: relationship.source });
    }
    if (!relationship.external && relationship.target && !nodeIds.has(relationship.target)) {
      issues.push({ severity: "warning", kind: "missing_target_node", relationship: relationship.id, target: relationship.target });
    }
    if (!relationship.summary) {
      issues.push({ severity: "info", kind: "relationship_missing_summary", relationship: relationship.id });
    }
  }

  for (const node of nodes) {
    const degree = (incoming.get(node.id) || 0) + (outgoing.get(node.id) || 0);
    if (degree === 0 && node.type !== "fragment") issues.push({ severity: "info", kind: "unlinked_node", node: node.id });
    if (!node.summary) issues.push({ severity: "info", kind: "node_missing_summary", node: node.id });
    if (!node.created_by) issues.push({ severity: "warning", kind: "node_missing_author", node: node.id });
    const normalizedSummary = normalizeComparableText(node.summary);
    const normalizedBody = normalizeComparableText(stripMarkdown(node.body || ""));
    if (normalizedSummary && normalizedBody && normalizedSummary === normalizedBody) {
      issues.push({
        severity: "warning",
        kind: "node_summary_duplicates_content",
        node: node.id
      });
    }
    if (node.type === "claim" && !relationships.some((rel) => rel.target === node.id && ["supports", "evidence_for", "derived_from", "cites"].includes(rel.type))) {
      issues.push({ severity: "warning", kind: "claim_without_visible_support", node: node.id });
    }
  }

  for (const warning of substrate.validation?.warnings || []) {
    issues.push({ severity: "warning", ...warning });
  }
  for (const error of substrate.validation?.errors || []) {
    issues.push({ severity: "error", ...error });
  }

  const penalty = issues.reduce((sum, issue) => {
    if (issue.severity === "error") return sum + 10;
    if (issue.severity === "warning") return sum + 4;
    return sum + 1;
  }, 0);
  const maxPenalty = Math.max(20, nodes.length * 6 + relationships.length * 2);
  const score = percentage(maxPenalty - penalty, maxPenalty);

  return {
    score,
    counts: {
      nodes: nodes.length,
      relationships: relationships.length,
      fragments: substrate.fragments?.length || 0,
      suggestions: substrate.suggestions?.length || 0,
      applied_suggestions: substrate.applied_suggestions?.length || 0,
      issues: issues.length,
      git_changes: gitStatus(rootDir).changed.length
    },
    valid: substrate.validation?.valid === true,
    issues,
    suggestions: substrate.suggestions || [],
    applied_suggestions: substrate.applied_suggestions || []
  };
}

import path from "node:path";
import { readJsonFile, writeJsonFile } from "./fs-utils.js";

export function importsPath(rootDir) {
  return path.join(rootDir, ".xananode", "imports.json");
}

export function loadImports(rootDir) {
  return readJsonFile(importsPath(rootDir), { imports: [] });
}

export function saveImports(rootDir, importsFile) {
  return writeJsonFile(importsPath(rootDir), importsFile);
}

export function addImport(rootDir, substrateImport) {
  if (!substrateImport?.id && !substrateImport?.url) throw new Error("Import requires an id or url");
  const file = loadImports(rootDir);
  const key = substrateImport.id || substrateImport.url;
  const entry = {
    id: substrateImport.id || key,
    url: substrateImport.url,
    version: substrateImport.version || "latest",
    mode: substrateImport.mode || "reference",
    path: substrateImport.path,
    added_at: substrateImport.added_at || new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
  const index = file.imports.findIndex((item) => (item.id || item.url) === key);
  if (index >= 0) file.imports[index] = { ...file.imports[index], ...entry };
  else file.imports.push(entry);
  saveImports(rootDir, file);
  return entry;
}

export function removeImport(rootDir, importId) {
  const file = loadImports(rootDir);
  const key = String(importId || "").trim();
  file.imports = file.imports.filter((item) => (item.id || item.url) !== key);
  saveImports(rootDir, file);
  return { id: key };
}

export function toggleImportNodeVisibility(rootDir, importId, nodeId, enabled = true) {
  const file = loadImports(rootDir);
  const key = String(importId || "").trim();
  const target = file.imports.find((item) => (item.id || item.url) === key);
  if (!target) throw new Error(`Unknown import: ${key}`);
  const disabled = new Set(Array.isArray(target.disabled_node_ids) ? target.disabled_node_ids : []);
  if (enabled) disabled.delete(nodeId);
  else disabled.add(nodeId);
  target.disabled_node_ids = [...disabled];
  target.updated_at = new Date().toISOString();
  saveImports(rootDir, file);
  return target;
}

